CREATE TABLE public.orders_raw (
    order_id integer,
    order_date date,
    customer_name text,
    customer_email text,
    customer_phone text,
    delivery_address text,
    product_names text,
    product_prices text,
    product_quantities text,
    total_amount numeric,
    status text
);


ALTER TABLE public.orders_raw OWNER TO inekrass;

